<?php
declare(strict_types=1);require __DIR__.'/../includes/bootstrap.php';require_role('lecturer');$page_title='Assigned Modules - SMIS';$lecturer=db_one('SELECT * FROM lecturers WHERE user_id=:id',['id'=>current_user()['id']]);$assignments=db_all('SELECT lm.*,m.code,m.title,m.credits,c.name class_name,s.name semester_name,s.academic_year,(SELECT COUNT(*) FROM students st JOIN student_modules sm ON sm.student_id=st.id WHERE st.class_id=lm.class_id AND sm.module_id=lm.module_id AND sm.semester_id=lm.semester_id) student_count FROM lecturer_modules lm JOIN modules m ON m.id=lm.module_id JOIN classes c ON c.id=lm.class_id JOIN semesters s ON s.id=lm.semester_id WHERE lm.lecturer_id=:id ORDER BY s.starts_on DESC,m.code',['id'=>$lecturer['id']]);
include __DIR__.'/../includes/header.php';?><div class="page-header"><h1>Assigned Modules</h1><p>Your classes and modules are allocated by the administrator.</p></div><div class="grid grid-col-3"><?php foreach($assignments as $a):?><div class="card"><div class="card-body"><span class="section-kicker"><?=e($a['class_name'])?></span><h2><?=e($a['code'])?></h2><p><?=e($a['title'])?></p><p class="text-muted"><?=e($a['semester_name'].' · '.$a['academic_year'])?> · <?=$a['student_count']?> students</p><div class="table-actions" style="margin-top:18px"><a class="btn btn-sm btn-primary" href="<?=url('lecturer/attendance.php?assignment='.$a['id'])?>">Attendance</a><a class="btn btn-sm btn-secondary" href="<?=url('lecturer/grades.php?assignment='.$a['id'])?>">Grades</a></div></div></div><?php endforeach?></div><?php include __DIR__.'/../includes/footer.php';?>
